export function AlmosaferLogo({ type = 'wordmark', variant = 'colour', lang = 'en', width, className, ...props }) {
  const key = type === 'wordmark' ? `wordmark:${variant}:${lang}` : `${type}:${variant}`
  const logo = logos[key]
  if (!logo) return null

  const [, , vbW, vbH] = logo.viewBox.split(' ').map(Number)
  const w = width ?? vbW
  const h = (w / vbW) * vbH

  return (
    <svg
      width={w}
      height={h}
      viewBox={logo.viewBox}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
      {...props}
    >
      {logo.paths.map((p, i) => <path key={i} {...p} />)}
    </svg>
  )
}
